// orders.controller.ts
import { Controller, Get, Patch, Param, Query, Body } from '@nestjs/common';
import { ApiTags, ApiOperation, ApiParam, ApiQuery, ApiResponse, ApiBody, ApiBearerAuth } from '@nestjs/swagger';
import { UpdateOrderStatusDto } from './dto/update-order-status.dto';

@ApiTags('Commandes')
@ApiBearerAuth('JWT-auth')
@Controller('orders')
export class OrdersController {
  @Get()
  @ApiOperation({ summary: 'Lister les commandes', description: 'Retourne la liste des commandes filtrée par statut optionnel' })
  @ApiQuery({ name: 'status', required: false, enum: ['pending', 'paid', 'shipped', 'delivered', 'cancelled'], description: 'Filtrer par statut' })
  @ApiResponse({ status: 200, description: 'Liste des commandes', type: [OrderResponseDto] })
  @ApiResponse({ status: 401, description: 'Non authentifié' })
  getOrders(@Query('status') status: string) {
    return this.ordersService.findAll(status);
  }

  @Get(':id')
  @ApiOperation({ summary: 'Récupérer une commande spécifique' })
  @ApiParam({ name: 'id', description: 'Identifiant de la commande', example: 'ORD-12345' })
  @ApiResponse({ status: 200, description: 'Commande trouvée', type: OrderResponseDto })
  @ApiResponse({ status: 404, description: 'Commande non trouvée' })
  getOrder(@Param('id') id: string) {
    return this.ordersService.findOne(id);
  }

  @Patch(':id/status')
  @ApiOperation({ summary: 'Mettre à jour le statut d'une commande' })
  @ApiParam({ name: 'id', description: 'Identifiant de la commande' })
  @ApiBody({ type: UpdateOrderStatusDto, description: 'Nouveau statut' })
  @ApiResponse({ status: 200, description: 'Statut mis à jour', type: OrderResponseDto })
  @ApiResponse({ status: 400, description: 'Statut invalide' })
  @ApiResponse({ status: 404, description: 'Commande non trouvée' })
  updateStatus(@Param('id') id: string, @Body() updateOrderStatusDto: UpdateOrderStatusDto) {
    return this.ordersService.updateStatus(id, updateOrderStatusDto.status);
  }
}
